export function getDrapeCdnUrl(slug: string, size?: string, archetype?: string): string | null {
  // Try archetype×size first, then archetype, then size, then base
  if (archetype && size) {
    const key = `${slug}_${archetype}_${size}`;
    if (DRAPE_CDN_URLS[key]) return DRAPE_CDN_URLS[key];
  }
  if (archetype) {
    const key = `${slug}_${archetype}`;
    if (DRAPE_CDN_URLS[key]) return DRAPE_CDN_URLS[key];
  }
  if (size) {
    const key = `${slug}_${size}`;
    if (DRAPE_CDN_URLS[key]) return DRAPE_CDN_URLS[key];
  }
  return DRAPE_CDN_URLS[slug] || null;
}